<div class="w-full flex justify-center"><svg viewbox="0 0 500 250" class="w-full max-w-md h-auto"> <!-- Conector de Ciclo (Líneas de flujo) --> <path d="M 100 170 Q 250 50 400 170" fill="none" stroke="#e0f2fe" stroke-width="8" stroke-dasharray="6,6"></path> <path d="M 400 170 Q 250 250 100 170" fill="none" stroke="#e0f2fe" stroke-width="8" stroke-dasharray="6,6"></path> <!-- Nodo 1: Evaporación --> <g class="concept-node" onclick="selectCycleNode('evaporacion')"> <circle cx="100" cy="170" r="40" fill="#fef08a" stroke="#eab308" stroke-width="3"></circle> <text x="100" y="175" font-family="'Fredoka', sans-serif" font-weight="bold" font-size="10" text-anchor="middle" fill="#854d0e">☀️ EVAPORACIÓN</text> </g> <!-- Nodo 2: Condensación --> <g class="concept-node" onclick="selectCycleNode('condensacion')"> <circle cx="250" cy="80" r="40" fill="#bae6fd" stroke="#0284c7" stroke-width="3"></circle> <text x="250" y="85" font-family="'Fredoka', sans-serif" font-weight="bold" font-size="10" text-anchor="middle" fill="#0369a1">☁️ CONDENSACIÓN</text> </g> <!-- Nodo 3: Precipitación --> <g class="concept-node" onclick="selectCycleNode('precipitacion')"> <circle cx="400" cy="170" r="40" fill="#93c5fd" stroke="#2563eb" stroke-width="3"></circle> <text x="400" y="175" font-family="'Fredoka', sans-serif" font-weight="bold" font-size="10" text-anchor="middle" fill="#1e40af">🌧️ PRECIPITACIÓN</text> </g> </svg></div>
