<p>
<script>
        // Diccionario de términos técnicos con soporte LaTeX para matemáticas (DUA)
        const glossaryData = {
            sequia: {
                title: "🌵 La Sequía",
                desc: "Es cuando en un lugar pasa mucho tiempo sin llover y los ríos, pantanos y pozos empiezan a quedarse vacíos. Nos quedamos sin agua suficiente para beber o regar las plantas.",
                picto: "🏜️",
                math: "Afecta a la disponibilidad de agua dulce, que representa solo el $3\\%$ del agua total de la Tierra."
            },
            hidrosfera: {
                title: "🌎 La Hidrosfera",
                desc: "Es todo el agua que hay en el planeta Tierra. ¡Está por todas partes! Incluye el agua de los océanos, ríos, lagos, el hielo de los polos y el vapor de agua que forma las nubes.",
                picto: "💧",
                math: "La hidrosfera cubre aproximadamente las $\\frac{3}{4}$ partes de la superficie terrestre."
            },
            fraccion: {
                title: "🍕 Las Fracciones",
                desc: "Es una forma de representar que dividimos algo entero en partes exactamente iguales. Por ejemplo, si dividimos una jarra en cuatro vasos iguales, cada vaso es una parte del total.",
                picto: "➗",
                math: "Se escribe como un número sobre otro: $\\frac{1}{4}$ (un cuarto) o $\\frac{1}{2}$ (un medio)."
            },
            capacidad: {
                title: "🏺 La Capacidad",
                desc: "Es la cantidad de líquido que cabe dentro de un recipiente (como una botella, un cubo o una piscina). Se mide utilizando la unidad del litro.",
                picto: "📏",
                math: "Recuerda la conversión clave: $1\\text{ litro } (1\\text{ L}) = 100\\text{ centilitros } (100\\text{ cL})$."
            },
            licencias: {
                title: "🎨 Creative Commons",
                desc: "Son unas reglas divertidas que nos permiten usar las fotos, dibujos o música que otras personas han subido a internet de forma legal y segura, siempre que les demos las gracias y citemos su autoría.",
                picto: "⚖️",
                math: "Se representa mediante símbolos como (CC) (BY) (NC) (SA)."
            }
        };

        // Datos del ciclo del agua para el mapa visual
        const cycleData = {
            evaporacion: {
                title: "☀️ Evaporación (Fase 1)",
                desc: "El calor del sol calienta el agua líquida de los ríos y mares. El agua se convierte en vapor invisible y sube flotando hacia el cielo.",
                soundFreq: 300
            },
            condensacion: {
                title: "☁️ Condensación (Fase 2)",
                desc: "Al subir al cielo, el vapor se enfría debido a la altura. El vapor vuelve a convertirse en gotitas de agua líquida muy pequeñas, que se juntan y forman las nubes.",
                soundFreq: 450
            },
            precipitacion: {
                title: "🌧️ Precipitación (Fase 3)",
                desc: "Cuando las nubes se llenan de muchas gotitas de agua y pesan demasiado, el agua cae hacia el suelo en forma de lluvia, nieve o granizo.",
                soundFreq: 600
            }
        };

        let currentFontScale = 1;
        let activeReadingBlock = null;

        // --- SISTEMA DE AUDIO EFECTOS (SINTETIZADOR WEB AUDIO API) ---
        function playCycleSound(frequency) {
            try {
                const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
                const oscillator = audioCtx.createOscillator();
                const gainNode = audioCtx.createGain();

                oscillator.connect(gainNode);
                gainNode.connect(audioCtx.destination);

                oscillator.type = 'sine';
                oscillator.frequency.setValueAtTime(frequency, audioCtx.currentTime);
                // Efecto de burbuja ascendente
                oscillator.frequency.exponentialRampToValueAtTime(frequency * 1.5, audioCtx.currentTime + 0.3);

                gainNode.gain.setValueAtTime(0.15, audioCtx.currentTime);
                gainNode.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.3);

                oscillator.start();
                oscillator.stop(audioCtx.currentTime + 0.3);
            } catch (e) {
                console.log("Audio no compatible.");
            }
        }

        // --- SISTEMA DE DICCIONARIO EMERGENTE ---
        function showGlossary(termKey) {
            const term = glossaryData[termKey];
            if (!term) return;

            const card = document.getElementById('glossary-card');
            card.className = "bg-white rounded-2xl p-5 border-2 border-emerald-400 text-left space-y-3 transition-all transform scale-100 shadow-md";

            card.innerHTML = `
                <div class="flex items-center gap-3">
                    <span class="text-3xl">${term.picto}</span>
                    <h4 class="font-bold text-emerald-800 text-lg font-fun">${term.title}</h4>
                </div>
                <p class="text-xs text-slate-600 leading-relaxed">${term.desc}</p>
                <div class="bg-emerald-50 p-3 rounded-xl border border-emerald-100 text-xs text-emerald-900 font-mono">
                    <strong>🧮 Sabías que...</strong>
                    <p class="mt-1">${term.math}</p>
                </div>
                <button onclick="speakTextOnly('${term.title}. ${term.desc}')" class="w-full py-2 bg-emerald-500 hover:bg-emerald-600 text-white font-bold text-xs rounded-xl flex items-center justify-center gap-2 transition-all">
                    🔊 Escuchar definición
                </button>
            `;

            // Re-renderizar las matemáticas de KaTeX añadidas dinámicamente
            renderMathInElement(card);
        }

        // --- MAPA CONCEPTUAL INTERACTIVO ---
        function selectCycleNode(nodeKey) {
            const data = cycleData[nodeKey];
            if (!data) return;

            // Reproducir sonido personalizado
            playCycleSound(data.soundFreq);

            // Actualizar panel inferior
            const expBlock = document.getElementById('cycle-explanation');
            const expTitle = document.getElementById('cycle-title');
            const expDesc = document.getElementById('cycle-desc');

            expBlock.classList.remove('hidden');
            expTitle.textContent = data.title;
            expDesc.textContent = data.desc;

            // Leer de forma automática
            speakTextOnly(`${data.title}. ${data.desc}`);
        }

        // --- ACCESIBILIDAD: LECTOR DE VOZ NATIVO (TEXT-TO-SPEECH) ---
        let currentUtterance = null;

        function speakText(textId, blockId) {
            const synth = window.speechSynthesis;
            if (synth.speaking) {
                synth.cancel();
                if (activeReadingBlock) {
                    document.getElementById(activeReadingBlock).classList.remove('ring-4', 'ring-sky-300', 'bg-sky-50/20');
                }
            }

            const textToRead = document.getElementById(textId).innerText;
            currentUtterance = new SpeechSynthesisUtterance(textToRead);
            currentUtterance.lang = 'es-ES';

            // Marcador visual (Resaltar bloque activo)
            const block = document.getElementById(blockId);
            block.classList.add('ring-4', 'ring-sky-300', 'bg-sky-50/20');
            activeReadingBlock = blockId;

            document.getElementById('globalStopBtn').classList.remove('hidden');

            currentUtterance.onend = () => {
                block.classList.remove('ring-4', 'ring-sky-300', 'bg-sky-50/20');
                document.getElementById('globalStopBtn').classList.add('hidden');
                activeReadingBlock = null;
            };

            synth.speak(currentUtterance);
        }

        function speakTextOnly(text) {
            const synth = window.speechSynthesis;
            if (synth.speaking) {
                synth.cancel();
            }
            const utterance = new SpeechSynthesisUtterance(text);
            utterance.lang = 'es-ES';
            synth.speak(utterance);
        }

        function stopSpeech() {
            window.speechSynthesis.cancel();
            if (activeReadingBlock) {
                document.getElementById(activeReadingBlock).classList.remove('ring-4', 'ring-sky-300', 'bg-sky-50/20');
            }
            document.getElementById('globalStopBtn').classList.add('hidden');
            activeReadingBlock = null;
        }

        // --- ACCESIBILIDAD: AJUSTES DE FUENTE Y CONTRASTE ---
        function changeFontSize(action) {
            const elements = document.querySelectorAll('p, li, article, h2, h3');
            if (action === 'increase' && currentFontScale < 1.3) {
                currentFontScale += 0.05;
            } else if (action === 'decrease' && currentFontScale > 0.85) {
                currentFontScale -= 0.05;
            }
            elements.forEach(el => {
                el.style.fontSize = `${14 * currentFontScale}px`;
            });
        }

        let contrastActive = false;
        function toggleContrast() {
            contrastActive = !contrastActive;
            const body = document.body;
            const btn = document.getElementById('contrastBtn');
            if (contrastActive) {
                body.classList.remove('bg-f0fdf4');
                body.style.backgroundColor = '#1e293b'; // Contraste oscuro accesible
                body.classList.add('text-white');
                btn.className = "px-4 py-2 bg-yellow-400 hover:bg-yellow-500 text-slate-900 font-bold rounded-xl text-sm transition-all";
            } else {
                body.style.backgroundColor = '#f0fdf4';
                body.classList.remove('text-white');
                btn.className = "px-4 py-2 bg-slate-100 hover:bg-slate-200 font-bold rounded-xl text-sm transition-all";
            }
        }
    </script>
