            { id: 9, name: "Alumno 9", plickers: 3, rubricH: 3, rubricM: 3, rubricO: 3, rubricC: 3, rubricCp: 3 },
            { id: 10, name: "Alumno 10", plickers: 4, rubricH: 4, rubricM: 3, rubricO: 3, rubricC: 4, rubricCp: 4 },
            { id: 11, name: "Alumno 11", plickers: 2, rubricH: 2, rubricM: 3, rubricO: 2, rubricC: 2, rubricCp: 3 },
            { id: 12, name: "Alumno 12", plickers: 5, rubricH: 4, rubricM: 4, rubricO: 4, rubricC: 4, rubricCp: 4 },
            { id: 13, name: "Alumno 13", plickers: 4, rubricH: 3, rubricM: 3, rubricO: 3, rubricC: 3, rubricCp: 4 },
            { id: 14, name: "Alumno 14", plickers: 3, rubricH: 3, rubricM: 2, rubricO: 3, rubricC: 3, rubricCp: 3 },
            { id: 15, name: "Alumno 15 (Rep.)", plickers: 4, rubricH: 4, rubricM: 3, rubricO: 4, rubricC: 4, rubricCp: 4 }
        ];

        let activeTab = 'register';
        let activeFormula = '';

        // Escala andaluza para rúbrica de 1 a 4 convertida a 10 puntos en Séneca
        function convertRubricScale(val) {
            if (val == 4) return 10;
            if (val == 3) return 7.5;
            if (val == 2) return 5.0;
            return 2.5;
        }

        function renderSpreadsheet() {
            const bodyReg = document.getElementById('bodyRegister');
            const bodySen = document.getElementById('bodySeneca');

            bodyReg.innerHTML = '';
            bodySen.innerHTML = '';

            alumnosData.forEach((alumno, index) => {
                const rowNum = index + 2; // Fila 1 es cabecera

                // Tabla 1: Registro Crudo
                const trReg = document.createElement('tr');
                trReg.innerHTML = `
                    <td class="text-center font-bold bg-gray-50 text-gray-500">${rowNum}</td>
                    <td class="font-semibold text-slate-800">${alumno.name}</td>
                    <td class="text-center"><input type="number" min="0" max="5" value="${alumno.plickers}" onchange="updateValue(${index}, 'plickers', this.value)" class="w-16 text-center border-0 bg-transparent focus:ring-1 focus:ring-emerald-500 rounded font-mono"></td>
                    <td class="text-center"><input type="number" min="1" max="4" value="${alumno.rubricH}" onchange="updateValue(${index}, 'rubricH', this.value)" class="w-16 text-center border-0 bg-transparent focus:ring-1 focus:ring-emerald-500 rounded font-mono"></td>
                    <td class="text-center"><input type="number" min="1" max="4" value="${alumno.rubricM}" onchange="updateValue(${index}, 'rubricM', this.value)" class="w-16 text-center border-0 bg-transparent focus:ring-1 focus:ring-emerald-500 rounded font-mono"></td>
                    <td class="text-center"><input type="number" min="1" max="4" value="${alumno.rubricO}" onchange="updateValue(${index}, 'rubricO', this.value)" class="w-16 text-center border-0 bg-transparent focus:ring-1 focus:ring-emerald-500 rounded font-mono"></td>
                    <td class="text-center"><input type="number" min="1" max="4" value="${alumno.rubricC}" onchange="updateValue(${index}, 'rubricC', this.value)" class="w-16 text-center border-0 bg-transparent focus:ring-1 focus:ring-emerald-500 rounded font-mono"></td>
                    <td class="text-center"><input type="number" min="1" max="4" value="${alumno.rubricCp}" onchange="updateValue(${index}, 'rubricCp', this.value)" class="w-16 text-center border-0 bg-transparent focus:ring-1 focus:ring-emerald-500 rounded font-mono"></td>
                `;
                // Eventos de selección para ver fórmulas
                trReg.querySelectorAll('td').forEach((td, colIdx) => {
                    td.addEventListener('click', () => selectCell('register', rowNum, colIdx, alumno));
                });
                bodyReg.appendChild(trReg);

                // Cálculos automáticos de los criterios
                const plickersScaled = (alumno.plickers / 5) * 10;
                const scoreCMN_1_1 = ((plickersScaled * 0.3) + (convertRubricScale(alumno.rubricH) * 0.7)).toFixed(2);
                const scoreCMN_1_4 = ((plickersScaled * 0.3) + (convertRubricScale(alumno.rubricH) * 0.7)).toFixed(2);
                const scoreMAT_1_2 = ((plickersScaled * 0.3) + (convertRubricScale(alumno.rubricM) * 0.7)).toFixed(2);
                const scoreLCL_3_1 = convertRubricScale(alumno.rubricO).toFixed(2);
                const scoreCD_3 = convertRubricScale(alumno.rubricC).toFixed(2);
                const scoreCPSAA_3 = convertRubricScale(alumno.rubricCp).toFixed(2);

                // Tabla 2: Volcado Séneca
                const trSen = document.createElement('tr');
                trSen.innerHTML = `
                    <td class="text-center font-bold bg-gray-50 text-gray-500">${rowNum}</td>
                    <td class="font-semibold text-slate-800">${alumno.name}</td>
                    <td class="text-center font-mono font-semibold text-emerald-700 bg-emerald-50/30">${scoreCMN_1_1}</td>
                    <td class="text-center font-mono font-semibold text-emerald-700 bg-emerald-50/30">${scoreCMN_1_4}</td>
                    <td class="text-center font-mono font-semibold text-amber-700 bg-amber-50/30">${scoreMAT_1_2}</td>
                    <td class="text-center font-mono font-semibold text-purple-700 bg-purple-50/30">${scoreLCL_3_1}</td>
                    <td class="text-center font-mono font-semibold text-blue-700 bg-blue-50/30">${scoreCD_3}</td>
                    <td class="text-center font-mono font-semibold text-slate-700 bg-slate-50/30">${scoreCPSAA_3}</td>
                `;
                trSen.querySelectorAll('td').forEach((td, colIdx) => {
                    td.addEventListener('click', () => selectCell('seneca', rowNum, colIdx, alumno));
                });
                bodySen.appendChild(trSen);
            });
        }

        function updateValue(index, field, value) {
            alumnosData[index][field] = parseFloat(value);
            renderSpreadsheet();
            showToast("Notas actualizadas. Fórmulas recalculadas.");
        }

        // Simula la selección de celdas para copiar fórmulas en LibreOffice Calc
        function selectCell(tableType, rowNum, colIdx, alumno) {
            // Limpiar clases previas
            document.querySelectorAll('.calc-grid td').forEach(td => td.classList.remove('selected-cell'));

            // Añadir clase a la celda clicada
            event.currentTarget.classList.add('selected-cell');

            const colsRegister = ["A", "B", "C", "D", "E", "F", "G"];
            const colsSeneca = ["A", "H", "I", "J", "K", "L", "M"];
            const curCol = tableType === 'register' ? colsRegister[colIdx] : colsSeneca[colIdx];

            document.getElementById('cellAddress').textContent = `${curCol}${rowNum}`;
            document.getElementById('statusSelection').textContent = `Celda seleccionada: ${curCol}${rowNum} | Fila: ${rowNum} | Columna: ${colIdx}`;

            // Determinar la fórmula matemática en castellano (Formato LibreOffice)
            let formula = '';
            if (tableType === 'register') {
                if (colIdx === 0) formula = `ROW_NUM: ${rowNum}`;
                else if (colIdx === 1) formula = `"${alumno.name}"`;
                else if (colIdx === 2) formula = `${alumno.plickers} (Aciertos directos)`;
                else formula = `${alumno[`rubric${colsRegister[colIdx]}`]} (Puntuación de Rúbrica 1-4)`;
            } else {
                if (colIdx === 0) formula = `ROW_NUM: ${rowNum}`;
                else if (colIdx === 1) formula = `"${alumno.name}"`;
                else if (colIdx === 2) formula = `=REDONDEAR(((B${rowNum}/5)*10)*0,3 + SI(C${rowNum}=4;10;SI(C${rowNum}=3;7,5;SI(C${rowNum}=2;5;2,5)))*0,7; 2)`;
                else if (colIdx === 3) formula = `=REDONDEAR(((B${rowNum}/5)*10)*0,3 + SI(C${rowNum}=4;10;SI(C${rowNum}=3;7,5;SI(C${rowNum}=2;5;2,5)))*0,7; 2)`;
                else if (colIdx === 4) formula = `=REDONDEAR(((B${rowNum}/5)*10)*0,3 + SI(D${rowNum}=4;10;SI(D${rowNum}=3;7,5;SI(D${rowNum}=2;5;2,5)))*0,7; 2)`;
                else if (colIdx === 5) formula = `=SI(E${rowNum}=4;10;SI(E${rowNum}=3;7,5;SI(E${rowNum}=2;5;2,5)))`;
                else if (colIdx === 6) formula = `=SI(F${rowNum}=4;10;SI(F${rowNum}=3;7,5;SI(F${rowNum}=2;5;2,5)))`;
                else if (colIdx === 7) formula = `=SI(G${rowNum}=4;10;SI(G${rowNum}=3;7,5;SI(G${rowNum}=2;5;2,5)))`;
            }

            activeFormula = formula;
            document.getElementById('formulaInput').textContent = formula;
            document.getElementById('formulaViewer').textContent = formula;
        }

        function copyActiveFormula() {
            if (!activeFormula) {
                showToast("Por favor, selecciona primero una celda.");
                return;
            }
            navigator.clipboard.writeText(activeFormula);
            showToast("¡Fórmula copiada! Ya puedes pegarla en tu LibreOffice Calc.");
        }

        function switchTab(tab) {
            activeTab = tab;
            document.getElementById('tabRegister').className = tab === 'register' ? "px-4 py-2 bg-white text-gray-800 font-bold text-xs rounded-lg shadow-sm transition-all" : "px-4 py-2 hover:bg-white text-gray-600 hover:text-gray-800 font-bold text-xs rounded-lg transition-all";
            document.getElementById('tabSeneca').className = tab === 'seneca' ? "px-4 py-2 bg-white text-gray-800 font-bold text-xs rounded-lg shadow-sm transition-all" : "px-4 py-2 hover:bg-white text-gray-600 hover:text-gray-800 font-bold text-xs rounded-lg transition-all";

            if (tab === 'register') {
                document.getElementById('tableRegister').classList.remove('hidden');
                document.getElementById('tableSeneca').classList.add('hidden');
            } else {
                document.getElementById('tableRegister').classList.add('hidden');
                document.getElementById('tableSeneca').classList.remove('hidden');
            }
        }

        // Exportación de datos compatible con el importador de la Junta de Andalucía (.csv)
        function exportToCSV() {
            let csvContent = "data:text/csv;charset=utf-8,";
            csvContent += "Alumno;CMN.4.A.1.1;CMN.4.A.1.4;MAT.4.B.1.2;LCL.4.B.3.1;CD.3;CPSAA.3\n";

            alumnosData.forEach(alumno => {
                const plickersScaled = (alumno.plickers / 5) * 10;
                const scoreCMN_1_1 = ((plickersScaled * 0.3) + (convertRubricScale(alumno.rubricH) * 0.7)).toFixed(2);
                const scoreCMN_1_4 = ((plickersScaled * 0.3) + (convertRubricScale(alumno.rubricH) * 0.7)).toFixed(2);
                const scoreMAT_1_2 = ((plickersScaled * 0.3) + (convertRubricScale(alumno.rubricM) * 0.7)).toFixed(2);
                const scoreLCL_3_1 = convertRubricScale(alumno.rubricO).toFixed(2);
                const scoreCD_3 = convertRubricScale(alumno.rubricC).toFixed(2);
                const scoreCPSAA_3 = convertRubricScale(alumno.rubricCp).toFixed(2);

                csvContent += `"${alumno.name}";${scoreCMN_1_1};${scoreCMN_1_4};${scoreMAT_1_2};${scoreLCL_3_1};${scoreCD_3};${scoreCPSAA_3}\n`;
            });

            const encodedUri = encodeURI(csvContent);
            const link = document.createElement("a");
            link.setAttribute("href", encodedUri);
            link.setAttribute("download", "sda8_volcado_seneca.csv");
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            showToast("Archivo CSV descargado correctamente.");
        }

        function showToast(message) {
            const toast = document.getElementById('toast');
            document.getElementById('toastMessage').textContent = message;
            toast.classList.remove('translate-y-20', 'opacity-0');
            toast.classList.add('translate-y-0', 'opacity-100');

            setTimeout(() => {
                toast.classList.remove('translate-y-0', 'opacity-100');
                toast.classList.add('translate-y-20', 'opacity-0');
            }, 3000);
        }

        // Carga inicial
        window.onload = function() {
            renderSpreadsheet();
        }
    </script>
