<div class="max-w-5xl mx-auto space-y-8"><!-- CABECERA PRINCIPAL --><header class="bg-gradient-to-r from-sky-500 via-blue-600 to-indigo-600 rounded-3xl p-6 md:p-8 text-white shadow-xl relative overflow-hidden">
