        const profilesData = {
            tda: {
                name: "⚡ Alumno con TDA (Dificultades de Atención)",
                desc: "Presenta dificultades para mantener la atención sostenida en actividades de larga lectura o escritura continuada. Puede mostrar inquietud motora.",
                solution: "Estructuramos el itinerario mediante el Mapa de Aventuras (retos cortos). Se le asignan roles manipulativos en el aula (ej. medir agua real en las jarras, ábaco) y se le facilita la opción de grabadora de voz nativa en Canva en lugar de redactar."
            },
            atal: {
                name: "🗣️ Alumnado ATAL (Incorporación Tardía / Idioma)",
                desc: "Muestra dificultades en la decodificación del idioma y comprensión lectora inicial de términos técnicos en castellano (sequía, hidrosfera).",
                solution: "Todo el material cuenta con soporte pictográfico de apoyo. En matemáticas se utiliza jarras de agua física y tarjetas de fracciones de colores (enfoque C-P-A) para que el lenguaje no sea un límite a su lógica matemática."
            },
            estandar: {
                name: "🧑‍🎓 Alumnado Estándar",
                desc: "Sigue el ritmo de aula convencional, pero se beneficia de la clarificación visual y la gamificación para una comprensión científica profunda.",
                solution: "Participa de forma fluida en equipos cooperativos mixtos, sirviendo de andamiaje natural (ayuda entre iguales) para sus compañeros con dificultades lingüísticas, afianzando sus propias competencias socioemocionales."
            }
        };

        let currentScale = 1;
        let audioEnabled = true;
        let completedObjectives = [];

        // --- EFECTOS DE SONIDO NATIVOS (SINTETIZADOR WEB AUDIO API) ---
        function playSound(freq) {
            if (!audioEnabled) return;
            try {
                const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
                const osc = audioCtx.createOscillator();
                const gain = audioCtx.createGain();

                osc.connect(gain);
                gain.connect(audioCtx.destination);

                osc.type = 'triangle';
                osc.frequency.setValueAtTime(freq, audioCtx.currentTime);
                osc.frequency.exponentialRampToValueAtTime(freq * 1.3, audioCtx.currentTime + 0.15);

                gain.gain.setValueAtTime(0.08, audioCtx.currentTime);
                gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.25);

                osc.start();
                osc.stop(audioCtx.currentTime + 0.25);
            } catch (e) {
                console.log("Audio API no soportada.");
            }
        }

        // --- SISTEMA DE CONTROL DE ACCESIBILIDAD ---
        function changeFontSize(action) {
            if (action === 'increase' && currentScale < 1.25) {
                currentScale += 0.05;
            } else if (action === 'decrease' && currentScale > 0.85) {
                currentScale -= 0.05;
            }

            // Aplicar tamaño a todos los elementos clave
            const paragraphs = document.querySelectorAll('p, li, h4');
            paragraphs.forEach(el => {
                el.style.fontSize = `${14 * currentScale}px`;
            });
            playSound(350);
        }

        function toggleAudio() {
            audioEnabled = !audioEnabled;
            const btn = document.getElementById('audioBtn');
            btn.textContent = audioEnabled ? '🔊' : '🔇';
            if (audioEnabled) {
                playSound(440);
            }
        }

        // --- INTERACTIVIDAD DE OBJETIVOS ---
        function toggleObjective(id) {
            const index = completedObjectives.indexOf(id);
            const card = document.getElementById(`obj-${id}`);
            const check = document.getElementById(`check-${id}`);

            if (index > -1) {
                // Desmarcar
                completedObjectives.splice(index, 1);
                card.className = "p-4 bg-slate-50 hover:bg-emerald-50/50 rounded-2xl border border-slate-200 cursor-pointer transition-all flex items-start gap-3";
                check.textContent = "⚪";
                playSound(280);
            } else {
                // Marcar como completado
                completedObjectives.push(id);
                card.className = "p-4 bg-emerald-50/60 hover:bg-emerald-50 rounded-2xl border-2 border-emerald-400 cursor-pointer transition-all flex items-start gap-3 shadow-sm";
                check.textContent = "✅";
                playSound(523.25); // Sonido alegre
            }
        }

        // --- SELECCIONADOR DE PERFILES DUA ---
        function selectProfile(profileKey) {
            const data = profilesData[profileKey];
            if (!data) return;

            playSound(400);

            const panel = document.getElementById('profile-details');
            const nameEl = document.getElementById('profile-name');
            const descEl = document.getElementById('profile-desc');
            const solutionEl = document.getElementById('profile-solution');

            panel.classList.remove('hidden');
            nameEl.textContent = data.name;
            descEl.textContent = data.desc;
            solutionEl.textContent = data.solution;
        }
    </script>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

