<script>
        const formatLabel = (label) => {
            if (label.length <= 16) return label;
            const words = label.split(' ');
            const lines = [];
            let currentLine = '';
            words.forEach(word => {
                if ((currentLine + word).length > 16) {
                    if (currentLine) lines.push(currentLine.trim());
                    currentLine = word + ' ';
                } else {
                    currentLine += word + ' ';
                }
            });
            if (currentLine) lines.push(currentLine.trim());
            return lines;
        };

        const globalTooltipOptions = {
            callbacks: {
                title: function(tooltipItems) {
                    const item = tooltipItems[0];
                    const label = item.chart.data.labels[item.dataIndex];
                    return Array.isArray(label) ? label.join(' ') : label;
                }
            }
        };

        const ctxDemographics = document.getElementById('demographicsChart').getContext('2d');
        new Chart(ctxDemographics, {
            type: 'doughnut',
            data: {
                labels: [
                    formatLabel('Alumnado Estándar'),
                    formatLabel('Alumnado ATAL'),
                    formatLabel('Alumnado TDA'),
                    formatLabel('Alumnado Repetidor')
                ],
                datasets: [{
                    data: [11, 2, 1, 1],
                    backgroundColor: ['#0ea5e9', '#10b981', '#f59e0b', '#ef4444'],
                    borderWidth: 0,
                    hoverOffset: 4
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: { position: 'bottom' },
                    tooltip: globalTooltipOptions
                },
                cutout: '65%'
            }
        });

        const ctxSubjects = document.getElementById('subjectsChart').getContext('2d');
        new Chart(ctxSubjects, {
            type: 'polarArea',
            data: {
                labels: [
                    formatLabel('Conocimiento del Medio (Hidrosfera)'),
                    formatLabel('Matemáticas (Medida y Fracciones)'),
                    formatLabel('Lengua Castellana (Textos)'),
                    formatLabel('Educación Artística (Diseño)')
                ],
                datasets: [{
                    data: [40, 30, 20, 10],
                    backgroundColor: [
                        'rgba(2, 132, 199, 0.7)',
                        'rgba(245, 158, 11, 0.7)',
                        'rgba(16, 185, 129, 0.7)',
                        'rgba(139, 92, 246, 0.7)'
                    ],
                    borderWidth: 1
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: { position: 'bottom' },
                    tooltip: globalTooltipOptions
                },
                scales: {
                    r: {
                        ticks: { display: false }
                    }
                }
            }
        });

        const ctxPhases = document.getElementById('phasesChart').getContext('2d');
        new Chart(ctxPhases, {
            type: 'bar',
            data: {
                labels: [
                    formatLabel('Fase 1: Motivación'),
                    formatLabel('Fase 2: Activación'),
                    formatLabel('Fase 3: Exploración'),
                    formatLabel('Fase 4: Estructuración'),
                    formatLabel('Fase 5: Aplicación'),
                    formatLabel('Fase 6: Conclusión')
                ],
                datasets: [{
                    label: 'Número de Sesiones',
                    data: [1, 1, 2, 6, 3, 1],
                    backgroundColor: '#0ea5e9',
                    borderRadius: 6
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: { display: false },
                    tooltip: globalTooltipOptions
                },
                scales: {
                    y: {
                        beginAtZero: true,
                        ticks: { stepSize: 1 }
                    }
                }
            }
        });
    </script>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

