                agrupamiento: "Equipos de 3 o 4",
                espacio: "Pasillo principal"
            }
        ];

        // Estado del juego
        let offlineMode = false;
        let completedMissions = JSON.parse(localStorage.getItem('completedMissions')) || [];
        let activeMissionId = null;

        // Efecto de sonido analógico usando Web Audio API
        function playSuccessSound() {
            try {
                const ctx = new (window.AudioContext || window.webkitAudioContext)();
                const osc = ctx.createOscillator();
                const gain = ctx.createGain();
                osc.connect(gain);
                gain.connect(ctx.destination);

                // Nota agradable tipo "Logro"
                osc.frequency.setValueAtTime(523.25, ctx.currentTime); // C5
                osc.frequency.setValueAtTime(659.25, ctx.currentTime + 0.15); // E5
                osc.frequency.setValueAtTime(783.99, ctx.currentTime + 0.3); // G5
                gain.gain.setValueAtTime(0.1, ctx.currentTime);
                gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5);

                osc.start();
                osc.stop(ctx.currentTime + 0.5);
            } catch (e) {
                console.log("Audio no disponible en este navegador");
            }
        }

        function renderMissions() {
            const container = document.getElementById('missionsContainer');
            container.innerHTML = '';

            childMissions.forEach((mission, idx) => {
                const isCompleted = completedMissions.includes(mission.id);

                // Colores para el andamiaje visual por materias (DUA)
                let borderCol = "border-sky-400";
                let badgeBg = "bg-sky-100 text-sky-800";
                if (mission.materiaColor === 'emerald') {
                    borderCol = "border-emerald-400";
                    badgeBg = "bg-emerald-100 text-emerald-800";
                } else if (mission.materiaColor === 'purple') {
                    borderCol = "border-purple-400";
                    badgeBg = "bg-purple-100 text-purple-800";
                } else if (mission.materiaColor === 'amber') {
                    borderCol = "border-amber-400";
                    badgeBg = "bg-amber-100 text-amber-800";
                }

                const missionHTML = `
                    <div class="relative flex flex-col items-center w-full z-10">
                        <div class="w-full bg-white rounded-3xl p-5 shadow-md border-b-8 ${borderCol} cursor-pointer hover:shadow-lg hover:scale-[1.02] transition-all duration-300 relative overflow-hidden" onclick="openMission(${mission.id})">

                            <!-- Indicador de Completado -->
                            <div class="absolute top-4 right-4 flex items-center gap-1">
                                <span class="text-xs px-2 py-1 rounded-full font-bold uppercase ${badgeBg}">S${mission.id}</span>
                                <span id="check-${mission.id}" class="text-2xl ${isCompleted ? 'opacity-100' : 'opacity-20'}">
                                    ${isCompleted ? '✅' : '⚪'}
                                </span>
                            </div>

                            <span class="text-xs font-bold text-slate-400 block mb-1">${mission.fase}</span>
                            <h3 class="text-lg md:text-xl font-bold text-slate-800 flex items-center gap-2">
                                <span>${mission.icon}</span> ${mission.title}
                            </h3>
                            <p class="text-xs text-slate-500 mt-2 line-clamp-2">Haz clic para ver qué herramientas y materiales necesitas.</p>
                        </div>
                    </div>
                `;
                container.innerHTML += missionHTML;
            });

            updateProgressBar();
        }

        function updateProgressBar() {
            const total = childMissions.length;
            const completed = completedMissions.length;
            const percent = Math.round((completed / total) * 100);

            const bar = document.getElementById('progressBar');
            const text = document.getElementById('progressText');

            bar.style.width = `${percent}%`;
            text.textContent = `${percent}%`;
        }

        function openMission(id) {
            const mission = childMissions.find(m => m.id === id);
            if (!mission) return;

            activeMissionId = id;
            document.getElementById('modalPhase').textContent = mission.fase;
            document.getElementById('modalTitle').textContent = mission.title;
            document.getElementById('modalDesc').textContent = mission.descripcion;
            document.getElementById('modalTeam').textContent = mission.agrupamiento;
            document.getElementById('modalPlace').textContent = mission.espacio;

            const toolHeader = document.getElementById('toolHeader');
            const modalTool = document.getElementById('modalTool');

            if (offlineMode) {
                toolHeader.textContent = "🎒 MOCHILA SIN WIFI ACTIVA:";
                modalTool.textContent = mission.offlineTool;
                modalTool.className = "text-xs text-amber-800 font-bold";
            } else {
                toolHeader.textContent = "📱 HERRAMIENTA DIGITAL RECOMENDADA:";
                modalTool.textContent = mission.onlineTool;
                modalTool.className = "text-xs text-sky-800 font-medium";
            }

            // Cambiar el texto del botón del modal según si ya está completada o no
            const completeBtn = document.getElementById('modalCompleteBtn');
            if (completedMissions.includes(id)) {
                completeBtn.textContent = "Misión ya completada 🌟 (Desmarcar)";
                completeBtn.className = "flex-1 py-3 bg-red-400 hover:bg-red-500 text-white font-bold rounded-2xl shadow-md transition-all";
            } else {
                completeBtn.textContent = "¡Misión Cumplida! 👍";
                completeBtn.className = "flex-1 py-3 bg-sky-500 hover:bg-sky-600 text-white font-bold rounded-2xl shadow-md transition-all";
            }

            // Mostrar el modal con animación suave
            const modal = document.getElementById('missionModal');
            modal.classList.remove('hidden');
        }

        function closeModal() {
            document.getElementById('missionModal').classList.add('hidden');
        }

        document.getElementById('modalCompleteBtn').addEventListener('click', () => {
            if (!activeMissionId) return;

            const index = completedMissions.indexOf(activeMissionId);
            if (index > -1) {
                // Si ya estaba completada, la desmarcamos
                completedMissions.splice(index, 1);
            } else {
                // Si es nueva, la completamos y reproducimos la nota musical
                completedMissions.push(activeMissionId);
                playSuccessSound();
            }

            localStorage.setItem('completedMissions', JSON.stringify(completedMissions));
            renderMissions();
            closeModal();
        });

        const wifiBtn = document.getElementById('wifiToggleBtn');
        wifiBtn.addEventListener('click', () => {
            offlineMode = !offlineMode;
            const wifiIcon = document.getElementById('wifiIcon');
            const wifiText = document.getElementById('wifiText');

            if (offlineMode) {
                wifiBtn.classList.remove('bg-amber-500', 'hover:bg-amber-600');
                wifiBtn.classList.add('bg-red-500', 'hover:bg-red-600');
                wifiIcon.textContent = "🪵";
                wifiText.textContent = "Mochila Offline Activa";
            } else {
                wifiBtn.classList.remove('bg-red-500', 'hover:bg-red-600');
                wifiBtn.classList.add('bg-amber-500', 'hover:bg-amber-600');
                wifiIcon.textContent = "📡";
                wifiText.textContent = "Modo Online Activo";
            }

            renderMissions();
        });

        // Carga inicial al cargar el navegador
        window.onload = function() {
            renderMissions();
        }
    </script>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

