        let planBActive = false;
        let activeFilter = 'todas';

        function renderTasks() {
            const container = document.getElementById('tasksContainer');
            container.innerHTML = '';

            const filteredTasks = activeFilter === 'todas' 
                ? sdaTasks 
                : sdaTasks.filter(task => task.materia === activeFilter);

            filteredTasks.forEach((task, idx) => {
                const isLeft = idx % 2 === 0;

                // Color dinámico según la materia para andamiaje visual DUA
                let borderCol = 'border-sky-400';
                let bgBadge = 'bg-sky-100 text-sky-800';
                if(task.materia === 'CMN') {
                    borderCol = 'border-green-400';
                    bgBadge = 'bg-green-100 text-green-800';
                } else if(task.materia === 'MAT') {
                    borderCol = 'border-amber-400';
                    bgBadge = 'bg-amber-100 text-amber-800';
                } else if(task.materia === 'LCL') {
                    borderCol = 'border-purple-400';
                    bgBadge = 'bg-purple-100 text-purple-800';
                }

                const cardHTML = `
                    <div class="relative flex flex-col md:flex-row items-center md:justify-between w-full">
                        <!-- Conector de línea para responsive MD -->
                        <div class="absolute left-4 md:left-1/2 w-8 h-1 bg-sky-300 md:-translate-x-1/2 z-0 hidden sm:block"></div>

                        <!-- Tarjeta -->
                        <div class="w-full md:w-[45%] bg-white rounded-3xl p-6 shadow-md border-t-8 ${borderCol} relative z-10 transition-all duration-300 transform hover:-translate-y-1 hover:shadow-xl ${isLeft ? 'md:mr-auto' : 'md:ml-auto'}">
                            <span class="absolute top-4 right-4 text-xs font-bold uppercase tracking-wider px-2 py-1 rounded-full ${bgBadge}">
                                ${task.materiaFull}
                            </span>
                            <span class="text-xs font-bold text-sky-500 block mb-1">${task.fase}</span>
                            <h3 class="text-xl font-bold text-gray-800 mb-2">S${task.id}: ${task.title}</h3>

                            <p class="text-sm text-gray-600 mb-4">${task.descripcion}</p>

                            <!-- Metadatos de organización DUA -->
                            <div class="grid grid-cols-2 gap-2 text-xs bg-gray-50 p-3 rounded-2xl mb-4">
                                <div><strong>⏳ Tiempo:</strong> ${task.duracion}</div>
                                <div><strong>👥 Grupo:</strong> ${task.agrupamiento}</div>
                                <div class="col-span-2"><strong>📍 Espacio:</strong> ${task.espacio}</div>
                                <div class="col-span-2 text-[11px] text-gray-500">🎯 Criterio: ${task.criterio}</div>
                            </div>

                            <!-- Herramientas Reactivas -->
                            <div class="p-3 rounded-2xl transition-all duration-300 ${planBActive ? 'bg-amber-50 border border-amber-200' : 'bg-sky-50 border border-sky-100'}">
                                <span class="text-xs font-bold block mb-1 ${planBActive ? 'text-amber-800' : 'text-sky-800'}">
                                    ${planBActive ? '⚠️ PLAN B ACTIVO (Sin conexión):' : '🔌 HERRAMIENTA RECOMENDADA (Con conexión):'}
                                </span>
                                <p class="text-xs text-gray-700 font-medium">
                                    ${planBActive ? task.offlineTool : task.onlineTool}
                                </p>
                            </div>
                        </div>
                    </div>
                `;
                container.innerHTML += cardHTML;
            });
        }

        // Evento botón Plan B / Contingencia
        const configBtn = document.getElementById('contingencyToggle');
        configBtn.addEventListener('click', () => {
            planBActive = !planBActive;
            const btnIcon = document.getElementById('btnIcon');
            const btnText = document.getElementById('btnText');

            if(planBActive) {
                configBtn.classList.remove('bg-sky-500', 'hover:bg-sky-600');
                configBtn.classList.add('bg-amber-500', 'hover:bg-amber-600');
                btnIcon.textContent = '🔌';
                btnText.textContent = 'Restaurar Red Andared (Online)';
            } else {
                configBtn.classList.remove('bg-amber-500', 'hover:bg-amber-600');
                configBtn.classList.add('bg-sky-500', 'hover:bg-sky-600');
                btnIcon.textContent = '📡';
                btnText.textContent = 'Activar Plan B (Modo Offline)';
            }
            renderTasks();
        });

        // Filtrado de materias
        function filterTasks(materia) {
            activeFilter = materia;
            renderTasks();
        }

        // Carga inicial de la línea temporal
        renderTasks();
    </script>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

