</footer></div>
<script>
        // Configurar fecha de hoy
        document.getElementById('dateInput').valueAsDate = new Date();

        // Datos de las preguntas (Sectores)
        const sectors = [
            {
                id: 'cohesion',
                title: 'Sector 1: Cohesión',
                subtitle: '(Trabajo en Equipo)',
                question: '¿He ayudado a mis compañeros de equipo a preparar y montar nuestro stand de la feria?',
                color: '#0ea5e9', // Azul
                angle: Math.PI * 1.25 // Arriba-Izquierda
            },
            {
                id: 'ciencia',
                title: 'Sector 2: Ciencia',
                subtitle: '(El Ciclo del Agua)',
                question: '¿He comprendido cómo funciona el ciclo del agua en la naturaleza y sus estados físicos?',
                color: '#22c55e', // Verde
                angle: Math.PI * 1.75 // Arriba-Derecha
            },
            {
                id: 'expresion',
                title: 'Sector 3: Expresión',
                subtitle: '(Hablar en Público)',
                question: '¿Me he sentido seguro o segura a la hora de hablar ante el público de la feria?',
                color: '#f59e0b', // Naranja
                angle: Math.PI * 0.75 // Abajo-Izquierda
            },
            {
                id: 'compromiso',
                title: 'Sector 4: Compromiso',
                subtitle: '(Ahorro de Agua)',
                question: '¿Sé cómo ahorrar agua en mi colegio y en mi casa a partir de hoy?',
                color: '#ef4444', // Rojo
                angle: Math.PI * 0.25 // Abajo-Derecha
            }
        ];

        // Opciones de puntuación
        const ratingOptions = [
            { value: 1, emoji: '😡', label: 'Me ha costado' },
            { value: 2, emoji: '😕', label: 'Podría mejorar' },
            { value: 3, emoji: '🙂', label: 'Bastante bien' },
            { value: 4, emoji: '🤩', label: '¡Genial!' }
        ];

        // Estado de las puntuaciones
        let scores = {
            cohesion: 0,
            ciencia: 0,
            expresion: 0,
            compromiso: 0
        };

        function renderQuestions() {
            const container = document.getElementById('questions-container');

            sectors.forEach(sector => {
                const card = document.createElement('div');
                card.className = `glass-panel rounded-2xl p-5 border-l-4 transition-all duration-300 hover:shadow-lg`;
                card.style.borderLeftColor = sector.color;

                let buttonsHTML = ratingOptions.map(opt => `
                    <button 
                        onclick="setScore('${sector.id}', ${opt.value})"
                        id="btn-${sector.id}-${opt.value}"
                        class="emoji-btn flex flex-col items-center p-2 rounded-xl border-2 border-transparent bg-white hover:bg-gray-50 flex-1"
                        title="${opt.label}">
                        <span class="text-3xl mb-1 drop-shadow-sm">${opt.emoji}</span>
                        <span class="text-[10px] uppercase font-bold text-gray-500 text-center leading-tight">${opt.label}</span>
                    </button>
                `).join('');

                card.innerHTML = `
                    <div class="flex items-center gap-2 mb-2">
                        <h3 class="font-bold text-lg" style="color: ${sector.color}">${sector.title}</h3>
                        <span class="text-sm font-semibold text-gray-500">${sector.subtitle}</span>
                    </div>
                    <p class="text-gray-700 font-medium mb-4">${sector.question}</p>
                    <div class="flex justify-between gap-2">
                        ${buttonsHTML}
                    </div>
                `;
                container.appendChild(card);
            });
        }

        const canvas = document.getElementById('dianaCanvas');
        const ctx = canvas.getContext('2d');
        const centerX = canvas.width / 2;
        const centerY = canvas.height / 2;
        const maxRadius = 300; // Radio máximo de la diana

        function setScore(sectorId, value) {
            scores[sectorId] = value;

            // Actualizar UI de botones
            ratingOptions.forEach(opt => {
                const btn = document.getElementById(`btn-${sectorId}-${opt.value}`);
                if(btn) btn.classList.remove('active');
            });
            document.getElementById(`btn-${sectorId}-${value}`).classList.add('active');

            drawDiana();
            checkCompletion();
        }

        function drawDiana() {
            // Limpiar canvas
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Dibujar fondo suave
            ctx.fillStyle = '#f8fafc';
            ctx.beginPath();
            ctx.arc(centerX, centerY, maxRadius + 20, 0, Math.PI * 2);
            ctx.fill();

            // Dibujar Círculos Concéntricos (Niveles 1 al 4)
            ctx.lineWidth = 2;
            ctx.strokeStyle = '#e2e8f0'; // Gris muy clarito

            for (let i = 1; i <= 4; i++) {
                const radius = (maxRadius / 4) * i;
                ctx.beginPath();
                ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
                ctx.stroke();

                // Textos de niveles en el eje vertical
                ctx.fillStyle = '#cbd5e1';
                ctx.font = 'bold 16px Nunito';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                if(i === 1) ctx.fillText('1 (Mad)', centerX, centerY - radius + 15);
                else if(i === 4) ctx.fillText('4 (Glad)', centerX, centerY - radius + 15);
                else ctx.fillText(i.toString(), centerX, centerY - radius + 15);
            }

            // Dibujar Ejes Diagonales (X)
            ctx.beginPath();
            // Linea top-left a bottom-right
            ctx.moveTo(centerX + Math.cos(Math.PI * 1.25) * maxRadius, centerY + Math.sin(Math.PI * 1.25) * maxRadius);
            ctx.lineTo(centerX + Math.cos(Math.PI * 0.25) * maxRadius, centerY + Math.sin(Math.PI * 0.25) * maxRadius);
            // Linea top-right a bottom-left
            ctx.moveTo(centerX + Math.cos(Math.PI * 1.75) * maxRadius, centerY + Math.sin(Math.PI * 1.75) * maxRadius);
            ctx.lineTo(centerX + Math.cos(Math.PI * 0.75) * maxRadius, centerY + Math.sin(Math.PI * 0.75) * maxRadius);
            ctx.stroke();

            // Etiquetas de los Sectores
            sectors.forEach(sector => {
                const labelRadius = maxRadius + 50;
                const lx = centerX + Math.cos(sector.angle) * labelRadius;
                const ly = centerY + Math.sin(sector.angle) * labelRadius;

                ctx.fillStyle = sector.color;
                ctx.font = 'bold 22px Nunito';
                // Ajustar alineación según el cuadrante
                if(Math.cos(sector.angle) > 0) ctx.textAlign = 'left';
                else ctx.textAlign = 'right';

                ctx.fillText(sector.title, lx, ly - 10);

                ctx.fillStyle = '#64748b';
                ctx.font = '600 18px Nunito';
                ctx.fillText(sector.subtitle, lx, ly + 15);
            });

            // Solo dibujar si hay al menos 1 punto
            const activeSectors = sectors.filter(s => scores[s.id] > 0);

            if (activeSectors.length > 0) {
                ctx.beginPath();
                sectors.forEach((sector, index) => {
                    const score = scores[sector.id] || 0; 
                    // Si el score es 0, lo dibujamos en el centro o no lo unimos. 
                    // Para que se vea bonito mientras se rellena, unimos hacia el centro si no hay score.
                    const radius = (maxRadius / 4) * (score || 0.1); 

                    const x = centerX + Math.cos(sector.angle) * radius;
                    const y = centerY + Math.sin(sector.angle) * radius;

                    if (index === 0) ctx.moveTo(x, y);
                    else ctx.lineTo(x, y);
                });
                ctx.closePath();

                // Relleno poligonal semi-transparente
                ctx.fillStyle = 'rgba(14, 165, 233, 0.3)'; // Azul agua
                ctx.fill();

                // Borde del polígono
                ctx.lineWidth = 4;
                ctx.strokeStyle = '#0284c7'; // Azul oscuro
                ctx.stroke();

                // Dibujar los Puntos interactivos
                sectors.forEach(sector => {
                    const score = scores[sector.id];
                    if (score > 0) {
                        const radius = (maxRadius / 4) * score;
                        const x = centerX + Math.cos(sector.angle) * radius;
                        const y = centerY + Math.sin(sector.angle) * radius;

                        // Circulo blanco exterior
                        ctx.beginPath();
                        ctx.arc(x, y, 12, 0, Math.PI * 2);
                        ctx.fillStyle = '#ffffff';
                        ctx.fill();
                        ctx.lineWidth = 3;
                        ctx.strokeStyle = sector.color;
                        ctx.stroke();

                        // Circulo de color interior
                        ctx.beginPath();
                        ctx.arc(x, y, 6, 0, Math.PI * 2);
                        ctx.fillStyle = sector.color;
                        ctx.fill();
                    }
                });
            }
        }

        function checkCompletion() {
            // Verificar si todos los sectores tienen > 0
            const isComplete = Object.values(scores).every(score => score > 0);
            if (isComplete && document.getElementById('successMessage').classList.contains('hidden')) {
                // Pequeño retraso para que el usuario vea el último punto dibujarse
                setTimeout(() => {
                    fireConfetti();
                    document.getElementById('successMessage').classList.remove('hidden');
                    document.getElementById('successMessage').classList.add('flex');
                }, 500);
            }
        }

        function closeSuccessMessage() {
            document.getElementById('successMessage').classList.add('hidden');
            document.getElementById('successMessage').classList.remove('flex');
        }

        // Sistema simple de confeti usando el DOM
        function fireConfetti() {
            const colors = ['#0ea5e9', '#22c55e', '#f59e0b', '#ef4444', '#a855f7'];
            for(let i=0; i<50; i++) {
                const confetti = document.createElement('div');
                confetti.style.position = 'fixed';
                confetti.style.width = '10px';
                confetti.style.height = '10px';
                confetti.style.backgroundColor = colors[Math.floor(Math.random() * colors.length)];
                confetti.style.left = Math.random() * 100 + 'vw';
                confetti.style.top = '-10px';
                confetti.style.borderRadius = Math.random() > 0.5 ? '50%' : '0';
                confetti.style.zIndex = '9999';
                confetti.style.pointerEvents = 'none';
                document.body.appendChild(confetti);

                const anim = confetti.animate([
                    { transform: `translate3d(0,0,0) rotate(0deg)`, opacity: 1 },
                    { transform: `translate3d(${Math.random()*100 - 50}px, 100vh, 0) rotate(${Math.random()*360}deg)`, opacity: 0 }
                ], {
                    duration: Math.random() * 2000 + 1500,
                    easing: 'cubic-bezier(.37,0,.63,1)'
                });

                anim.onfinish = () => confetti.remove();
            }
        }

        // Descargar el Canvas como imagen tipo "Certificado"
        function downloadBadge() {
            const studentName = document.getElementById('studentName').value || 'Guardián';
            const teamName = document.getElementById('teamName').value || 'Sin Equipo';

            // Crear un canvas temporal para dibujar la insignia completa (con nombre y diana)
            const exportCanvas = document.createElement('canvas');
            exportCanvas.width = 1000;
            exportCanvas.height = 1100;
            const eCtx = exportCanvas.getContext('2d');

            // Fondo
            eCtx.fillStyle = '#f0fdf4'; // Fondo verdecito claro
            eCtx.fillRect(0, 0, exportCanvas.width, exportCanvas.height);

            // Decoración cabecera
            eCtx.fillStyle = '#0ea5e9';
            eCtx.fillRect(0, 0, exportCanvas.width, 120);

            // Textos Cabecera
            eCtx.fillStyle = '#ffffff';
            eCtx.font = 'bold 45px sans-serif';
            eCtx.textAlign = 'center';
            eCtx.fillText('Diana de Aprendizaje - Guardianes del Planeta Azul', exportCanvas.width/2, 60);

            eCtx.font = '24px sans-serif';
            eCtx.fillText(`Misión Completada por: ${studentName} (Equipo: ${teamName})`, exportCanvas.width/2, 100);

            // Dibujar la diana actual escalada al centro
            eCtx.drawImage(canvas, 100, 180, 800, 800);

            // Texto pie de página
            eCtx.fillStyle = '#64748b';
            eCtx.font = 'italic 20px sans-serif';
            const date = document.getElementById('dateInput').value;
            eCtx.fillText(`Registrado en la Fecha Estelar: ${date}`, exportCanvas.width/2, 1050);

            // Descargar
            const link = document.createElement('a');
            link.download = `Diana_Guardian_${studentName.replace(/\s+/g, '_')}.png`;
            link.href = exportCanvas.toDataURL('image/png');
            link.click();
        }

        // --- GEMINI API INTEGRATION ---
        const apiKey = ""; // El entorno inyecta la clave automáticamente

        async function callGeminiAPI(prompt) {
            const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-09-2025:generateContent?key=${apiKey}`;
            const payload = {
                contents: [{ parts: [{ text: prompt }] }],
                systemInstruction: { 
                    parts: [{ text: "Eres el 'Sabio del Agua', un mentor mágico y amable para niños de primaria. Tu misión es darles feedback sobre sus autoevaluaciones escolares. Usa un lenguaje motivador, empático, muy sencillo y alegre. Incluye emojis relacionados con la naturaleza y el agua. Nunca los regañes, dales ánimos si su nota es baja." }] 
                }
            };

            // Lógica de reintentos con retraso exponencial
            const maxRetries = 5;
            const delays = [1000, 2000, 4000, 8000, 16000];

            for (let i = 0; i < maxRetries; i++) {
                try {
                    const response = await fetch(url, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify(payload)
                    });

                    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

                    const result = await response.json();
                    return result.candidates?.[0]?.content?.parts?.[0]?.text || "¡Has hecho un gran trabajo reflexionando, joven guardián!";
                } catch (error) {
                    if (i === maxRetries - 1) {
                        console.error("Gemini API falló tras varios reintentos:", error);
                        return "¡Uy! Mis poderes mágicos de agua están recargándose. Pero te diré un secreto: ¡has hecho un gran trabajo evaluándote!";
                    }
                    await new Promise(res => setTimeout(res, delays[i]));
                }
            }
        }

        async function generateAIFeedback() {
            const btn = document.getElementById('btn-ai-feedback');
            const loading = document.getElementById('ai-loading');
            const textContainer = document.getElementById('ai-feedback-text');
            const studentName = document.getElementById('studentName').value || 'Joven Guardián';

            // Preparar UI para carga
            btn.classList.add('hidden');
            textContainer.classList.add('hidden');
            loading.classList.remove('hidden');
            loading.classList.add('flex');

            // Construir el prompt basado en las puntuaciones reales
            const scoreCohesion = ratingOptions.find(o => o.value === scores.cohesion)?.label || '';
            const scoreCiencia = ratingOptions.find(o => o.value === scores.ciencia)?.label || '';
            const scoreExpresion = ratingOptions.find(o => o.value === scores.expresion)?.label || '';
            const scoreCompromiso = ratingOptions.find(o => o.value === scores.compromiso)?.label || '';

            const prompt = `
                El alumno llamado "${studentName}" ha completado su diana de autoevaluación del proyecto "Guardianes del Planeta Azul". 
                Estas son sus puntuaciones (del 1 al 4, donde 1 es "Me ha costado" y 4 es "¡Genial!"):
                - Trabajo en equipo: ${scores.cohesion}/4 (${scoreCohesion})
                - Conocimiento del ciclo del agua: ${scores.ciencia}/4 (${scoreCiencia})
                - Hablar en público: ${scores.expresion}/4 (${scoreExpresion})
                - Compromiso con ahorrar agua: ${scores.compromiso}/4 (${scoreCompromiso})

                Por favor, escribe un breve mensaje (máximo 4-5 líneas) dirigiéndote a ${studentName}.
                Destaca positivamente su puntuación más alta y dale un breve y tierno consejo o estrategia para mejorar en su puntuación más baja. 
            `;

            // Llamar a la API de Gemini
            const feedbackText = await callGeminiAPI(prompt);

            // Mostrar el resultado
            loading.classList.add('hidden');
            loading.classList.remove('flex');

            // Reemplazar saltos de línea y formatear un poco (negritas si Gemini incluye Markdown)
            let formattedText = feedbackText.replace(/\n/g, '<br>');
            formattedText = formattedText.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');

            textContainer.innerHTML = formattedText;
            textContainer.classList.remove('hidden');
        }

        // Inicializar
        window.onload = () => {
            renderQuestions();
            drawDiana();
        };

    </script>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}
